<?php $title='Videos';require __DIR__.'/partials/header.php';?><div class="row g-4"><div class="col-lg-5"><div class="card mb-3"><div class="card-body"><h1 class="h4">Upload video</h1><form method="post" action="/videos/upload" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input class="form-control mb-3" type="file" name="video" accept="video/*" required><button class="btn btn-primary">Upload</button></form></div></div><div class="card"><div class="card-body"><h2 class="h5">Import from YouTube</h2><form method="post" action="/videos/import"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input class="form-control mb-3" type="url" name="url" placeholder="YouTube URL" required><button class="btn btn-outline-primary">Queue import</button></form></div></div></div><div class="col-lg-7"><h1 class="h4">Library</h1><div class="list-group mb-4"><?php foreach($videos as $v):?><div class="list-group-item"><div class="d-flex justify-content-between align-items-center"><div><strong><?=e($v['original_filename'])?></strong><div class="small text-secondary"><?=e($v['title'])?> · <?=number_format((int)$v['size_bytes']/1048576,1)?> MB</div></div><div class="btn-group"><button class="btn btn-sm btn-outline-primary" data-bs-toggle="collapse" data-bs-target="#rename-<?=$v['id']?>">Edit</button><a class="btn btn-sm btn-outline-secondary" href="/playlists">Stream</a><form method="post" action="/videos/delete" onsubmit="return confirm('Delete this video and remove it from every playlist?')"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="video_id" value="<?=$v['id']?>"><button class="btn btn-sm btn-outline-danger">Delete</button></form></div></div><form id="rename-<?=$v['id']?>" class="collapse mt-2" method="post" action="/videos/rename"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="video_id" value="<?=$v['id']?>"><input class="form-control form-control-sm d-inline-block w-75" name="title" value="<?=e($v['title'])?>"><button class="btn btn-sm btn-primary">Rename</button></form></div><?php endforeach?></div><h2 class="h5">Recent imports</h2><?php foreach($imports as $job):?><div class="small mb-1"><?=e($job['source_url'])?> <span class="badge text-bg-secondary"><?=e($job['status'])?></span></div><?php endforeach?></div></div><?php require __DIR__.'/partials/footer.php'; ?>
